body:
Given the following input,
```verilog
module pattern_gen (
    // avalon-st source
    input   ready,
    output  valid,
    output  reg sop,
    output  reg eop,
    output  [63:0] data,

    input   clk, rst_n
);

    localparam LENGTH = 64'd20 - 64'd1;

    reg     [63:0] ctr;
    reg     stop;

    // design an FSM 
    // idle -> start -> working -> end -> idle

    localparam [4:0]    // one hot
        IDLE    = 1,
        START   = 2,
        WORKING = 4,
        END     = 8;
    
    reg     [4:0] cstate, nstate;

    // define state flip flops
    always @ (posedge clk or negedge rst_n) begin 
        if (!rst_n) begin 
            cstate <= IDLE;
        end
        else begin 
            cstate <= nstate;
        end
    end

    // define state transitions
    always @ (*) begin 
        case (cstate)
            IDLE:       nstate = START;
            START:      nstate = ready ? WORKING : START;
            WORKING:    nstate = ready ? (stop ? END : WORKING) : WORKING;
            END:        nstate = ready ? IDLE : END;
            default:    nstate = IDLE;
        endcase
    end

    // define the counter and outputs
    always @ (posedge clk or negedge rst_n) begin 
        if (!rst_n) begin
            ctr <= 'b0;
        end
        else begin 
            case (nstate)
                IDLE:       ctr <= 'b0;
                START:      ctr <= 'b0;
                WORKING:    ctr <= ready ? ctr + 1'b1 : ctr;
                END:        ctr <= ctr;
                default:    ctr <= ctr;
            endcase
        end
    end

    always @ (*) begin 
        sop     = cstate == START;
        eop     = cstate == END;
        stop    = ctr == LENGTH;
    end

    assign valid = 1'b1;        // data is always valid
    assign data = ctr;
endmodule
```
synth_intel fails and yosys quits (crashes?) with the following error
```
2.23. Executing DFFINIT pass (set INIT param on FF cells).
ERROR: Multi-bit init value for pattern_gen.$auto$simplemap.cc:496:simplemap_adff$554.power_up is incompatible with -highlow mode.
```
However, if I run `synth_intel` after running `synth_xilinx`, it works fine
yosys built from git, Ubuntu 18.04 LTS

